module RefModule(
  input Vin,
  input Vth,
  input clk,
  input reset,
  output rst_out
);reg unused_bor_ff;

  always @ (posedge clk or negedge reset) begin
    if (!reset) begin
      unused_bor_ff <= 0;
    end else begin
      if (Vin < Vth) begin
        unused_bor_ff <= 1;
      end else begin
        unused_bor_ff <= 0;
      end
    end
  end

  assign rst_out = unused_bor_ff;

endmodule
